<!DOCTYPE html>
<html>
<head>
  <title>Maze Game</title>
  <style>
    body { font-family: sans-serif; }
    #maze { border: 1px solid black; margin: 20px; display: grid; }
    .wall { background-color: black; }
    .bot { width: 10px; height: 10px; background-color: red; position: absolute; }
    #completed { font-size: 20px; margin-bottom: 10px; }
    #timer { font-size: 16px; }
    #reset { padding: 10px 20px; background-color: lightblue; border: none; cursor: pointer; }
  </style>
</head>
<body>

  <h1>Maze Game</h1>

  <div id="completed">Bots Completed: 0</div>
  <div id="timer">Elapsed Time: 0ms</div>
  <button id="reset">Reset</button>

  <canvas id="maze" width="400" height="400"></canvas>

  <script>
    const mazeWidth = 25;
    const mazeHeight = 25;
    const cellSize = 20;
    const botSize = 10;
    const numBots = 24;

    let mazeData = [];
    let bots = [];
    let completed = 0;
    let elapsedMs = 0;
    let timerInterval;

    function generateMaze() {
      mazeData = Array(mazeHeight).fill(null).map(() => Array(mazeWidth).fill(false)); // false = wall

      // Create a simple maze structure (can be improved)
      for (let i = 1; i < mazeWidth - 1; i++) {
        mazeData[0][i] = true;
        mazeData[mazeHeight - 1][i] = true;
        for (let j = 1; j < mazeHeight - 1; j++) {
          if ((i + j) % 2 === 0) {
            mazeData[j][i] = true;
          }
        }
      }

      // Ensure a path to the exit
      let startX = 1;
      let startY = 1;
      let endX = mazeWidth - 2;
      let endY = mazeHeight - 2;

      mazeData[startY][startX] = true; // Start at top-left
      mazeData[endY][endX] = true;    // End at bottom-right

      // Simple path creation (very basic)
      for(let i=1; i<mazeHeight - 1; ++i){
          mazeData[i][startX] = true;
      }
      for(let j=1; j<mazeWidth - 1; ++j){
          mazeData[endY][j] = true;
      }

    }


    function drawMaze() {
      const canvas = document.getElementById('maze');
      const ctx = canvas.getContext('2d');
      canvas.width = mazeWidth * cellSize;
      canvas.height = mazeHeight * cellSize;

      for (let i = 0; i < mazeHeight; i++) {
        for (let j = 0; j < mazeWidth; j++) {
          if (mazeData[i][j]) {
            ctx.fillStyle = 'black';
            ctx.fillRect(j * cellSize, i * cellSize, cellSize, cellSize);
          }
        }
      }

      for (let i = 0; i < numBots; i++) {
        const bot = bots[i];
        ctx.fillStyle = 'red';
        ctx.fillRect(bot.x * cellSize + cellSize / 4, bot.y * cellSize + cellSize / 4, botSize, botSize);
      }
    }

    function updateHUD() {
      document.getElementById('completed').textContent = `Bots Completed: ${completed}`;
      document.getElementById('timer').textContent = `Elapsed Time: ${elapsedMs}ms`;
    }


    function tick(n) {
      elapsedMs += n;
      updateHUD();

      for (let i = 0; i < numBots; i++) {
        const bot = bots[i];
        if (!bot.finished) {
          // Simple movement - move one cell in a random direction
          const dx = Math.random() > 0.5 ? 1 : -1;
          const dy = Math.random() > 0.5 ? 1 : -1;

          let newX = bot.x + dx;
          let newY = bot.y + dy;

          if (newX >= 0 && newX < mazeWidth && newY >= 0 && newY < mazeHeight && !mazeData[newY][newX]) {
            bot.x = newX;
            bot.y = newY;
          }
          bot.finished = true;

          if (bot.x === mazeWidth - 2 && bot.y === mazeHeight - 2) {
            completed++;
          }
        }
      }
    }


    function resetGame() {
      completed = 0;
      elapsedMs = 0;
      bots = [];
      for (let i = 0; i < numBots; i++) {
        bots.push({ x: 1, y: 1, finished: false }); // Reset bots to start
      }
      generateMaze();
      drawMaze();
      updateHUD();
      timerInterval = setInterval(tick, 20);
    }

    window.game = {
      bots,
      completed,
      elapsedMs,
      tick: tick,
      reset: resetGame
    };

    generateMaze();
    drawMaze();
    updateHUD();

    document.getElementById('reset').addEventListener('click', resetGame);
  </script>

</body>
</html>
